w('middlewares/__init__.py', 'from .subscription import SubscriptionMiddleware\n\ndef setup(dp):\n    dp.middleware.setup(SubscriptionMiddleware())\n')

w('middlewares/subscription.py', 'from aiogram import types\nfrom aiogram.dispatcher.middlewares import BaseMiddleware\nfrom loader import bot\nfrom data.config import CHANNEL_ID\n\nEXEMPT_COMMANDS = ["/start", "/admin"]\n\n\nclass SubscriptionMiddleware(BaseMiddleware):\n    async def on_pre_process_message(self, message: types.Message, data: dict):\n        if message.text and any(message.text.startswith(cmd) for cmd in EXEMPT_COMMANDS):\n            return\n        if not CHANNEL_ID or CHANNEL_ID == "@speaking_bot_channel":\n            return\n        try:\n            member = await bot.get_chat_member(CHANNEL_ID, message.from_user.id)\n            if member.status in ["left", "kicked", "banned"]:\n                from keyboards.inline.subscription import subscribe_kb\n                await message.answer(\n                    "⚠️ Botdan foydalanish uchun kanalimizga obuna bo\'lishingiz shart!",\n                    reply_markup=subscribe_kb()\n                )\n                raise Exception("Not subscribed")\n        except Exception as e:\n            if "Not subscribed" in str(e):\n                raise\n            pass\n')

w('services/stt_service.py', 'import io\nfrom openai import AsyncOpenAI\nfrom data.config import OPENAI_API_KEY\n\nclient = AsyncOpenAI(api_key=OPENAI_API_KEY)\n\n\nasync def voice_to_text(voice, bot) -> str:\n    try:\n        file_info = await bot.get_file(voice.file_id)\n        file_bytes = await bot.download_file(file_info.file_path)\n        audio_data = io.BytesIO(file_bytes.getvalue())\n        audio_data.name = "voice.ogg"\n        resp = await client.audio.transcriptions.create(\n            model="whisper-1",\n            file=audio_data,\n            language="en"\n        )\n        return resp.text\n    except Exception as e:\n        print(f"STT error: {e}")\n        return None\n')

w('utils/scheduler.py', 'from apscheduler.schedulers.asyncio import AsyncIOScheduler\nfrom apscheduler.triggers.cron import CronTrigger\n\n\ndef setup_scheduler():\n    scheduler = AsyncIOScheduler(timezone="Asia/Tashkent")\n    scheduler.add_job(send_daily_reports, CronTrigger(hour=22, minute=0))\n    scheduler.start()\n    print("Scheduler started — daily reports at 22:00 Tashkent time")\n\n\nasync def send_daily_reports():\n    from loader import bot\n    from utils.db_api.crud import get_all_users, get_today_activity\n    from services.ai_service import generate_daily_report\n\n    users = await get_all_users()\n    for user in users:\n        activity = await get_today_activity(user.telegram_id)\n        if not activity:\n            continue\n        if activity.mocks_done == 0 and activity.words_looked == 0 and activity.ai_chats == 0:\n            continue\n        try:\n            activity_data = {\n                "mocks_done": activity.mocks_done,\n                "words_looked": activity.words_looked,\n                "ai_chats": activity.ai_chats,\n                "last_ielts_band": activity.last_ielts_band,\n                "last_cefr_score": activity.last_cefr_score,\n                "last_cefr_level": activity.last_cefr_level,\n            }\n            report = await generate_daily_report(activity_data)\n            text = f"📊 <b>Kunlik Hisobot</b>\n\n{report}"\n            await bot.send_message(user.telegram_id, text)\n        except Exception as e:\n            print(f"Daily report error for {user.telegram_id}: {e}")\n')

print("Phase 2 done")
w('services/ai_service.py', 'import json\nfrom openai import AsyncOpenAI\nfrom data.config import OPENAI_API_KEY\n\nclient = AsyncOpenAI(api_key=OPENAI_API_KEY)\n\n\nasync def lookup_word_ai(word: str) -> dict:\n    try:\n        resp = await client.chat.completions.create(\n            model="gpt-4o-mini",\n            messages=[\n                {"role": "system", "content": "You are an English dictionary and vocabulary expert."},\n                {"role": "user", "content": f\'For the word "{word}", return JSON with keys: word, level (A1/A2/B1/B2/C1/C2), definition (clear English), translation_uz (Uzbek translation), examples (list of 5 academic sentences).\'}\n            ],\n            response_format={"type": "json_object"},\n            max_tokens=600\n        )\n        return json.loads(resp.choices[0].message.content)\n    except Exception as e:\n        print(f"lookup_word_ai error: {e}")\n        return None\n\n\nasync def evaluate_ielts(questions: list, transcripts: list) -> dict:\n    qa_text = ""\n    for q, t in zip(questions, transcripts):\n        qa_text += f"[Part {q.get(\'part\',\'?\')}}] Q: {q.get(\'question\',\'\')}\nA: {t}\n\n"\n    try:\n        resp = await client.chat.completions.create(\n            model="gpt-4o",\n            messages=[\n                {"role": "system", "content": "You are a strict but fair IELTS Speaking examiner. Evaluate based on: Fluency & Coherence, Lexical Resource, Grammatical Range & Accuracy, Pronunciation. Give bands 1.0-9.0 in 0.5 increments."},\n                {"role": "user", "content": f"Evaluate this IELTS Speaking test:\n\n{qa_text}\n\nReturn JSON with: overall_band, sub_scores (fluency, lexical, grammar, pronunciation), strengths (list), improvements (list), mistakes (list of error/correction/explanation), recommendations (list)."}\n            ],\n            response_format={"type": "json_object"},\n            max_tokens=1200\n        )\n        return json.loads(resp.choices[0].message.content)\n    except Exception as e:\n        print(f"evaluate_ielts error: {e}")\n        return {"overall_band": 5.0, "sub_scores": {}, "strengths": [], "improvements": ["Server error"], "mistakes": [], "recommendations": []}\n\n\nasync def evaluate_cefr(questions: list, transcripts: list) -> dict:\n    qa_text = ""\n    for q, t in zip(questions, transcripts):\n        qa_text += f"[Part {q.get(\'part\',\'?\')}}] Q: {q.get(\'question\',\'\')}\nA: {t}\n\n"\n    try:\n        resp = await client.chat.completions.create(\n            model="gpt-4o",\n            messages=[\n                {"role": "system", "content": "You are a CEFR language examiner. Score 1-75: A1(1-14), A2(15-34), B1(35-50), B2(51-65), C1(66-75). Evaluate: Range, Accuracy, Fluency, Interaction, Coherence."},\n                {"role": "user", "content": f"Evaluate this CEFR Speaking test:\n\n{qa_text}\n\nReturn JSON with: score (int 1-75), level (A1/A2/B1/B2/C1/C2), feedback (object with summary, strengths list, improvements list, errors list of error/correction/explanation)."}\n            ],\n            response_format={"type": "json_object"},\n            max_tokens=1000\n        )\n        return json.loads(resp.choices[0].message.content)\n    except Exception as e:\n        print(f"evaluate_cefr error: {e}")\n        return {"score": 40, "level": "B1", "feedback": {"summary": "Error occurred", "strengths": [], "improvements": [], "errors": []}}\n\n\nasync def chat_with_coach(history: list) -> str:\n    try:\n        resp = await client.chat.completions.create(\n            model="gpt-4o-mini",\n            messages=history,\n            max_tokens=300\n        )\n        return resp.choices[0].message.content\n    except Exception as e:\n        print(f"chat_with_coach error: {e}")\n        return "Sorry, I had a technical issue. Please try again!"\n\n\nasync def generate_roadmap(ielts_band: float = None, cefr_score: int = None, cefr_level: str = None, total_mocks: int = 0) -> str:\n    level_info = ""\n    if ielts_band:\n        level_info += f"IELTS Band: {ielts_band}\n"\n    if cefr_level and cefr_score:\n        level_info += f"CEFR Level: {cefr_level} (Score: {cefr_score}/75)\n"\n    if total_mocks:\n        level_info += f"Total mocks done: {total_mocks}\n"\n    if not level_info:\n        level_info = "Beginner level (no tests taken yet)"\n    try:\n        resp = await client.chat.completions.create(\n            model="gpt-4o-mini",\n            messages=[\n                {"role": "system", "content": "You are an expert English learning coach creating personalized study roadmaps."},\n                {"role": "user", "content": f"Create a personalized English speaking improvement roadmap for a student.\n\nCurrent level:\n{level_info}\n\nCreate a 4-week roadmap with daily activities, key resources, and target score. Format nicely with emojis. Keep it practical and motivating."}\n            ],\n            max_tokens=800\n        )\n        return resp.choices[0].message.content\n    except Exception as e:\n        return "Roadmap yaratishda xato. Keyinroq urinib ko\'ring."\n\n\nasync def generate_daily_report(activity_data: dict) -> str:\n    try:\n        resp = await client.chat.completions.create(\n            model="gpt-4o-mini",\n            messages=[\n                {"role": "system", "content": "You are an encouraging English learning coach."},\n                {"role": "user", "content": f"Generate a brief daily report in Uzbek language (3-4 sentences, encouraging) for a student with this activity: mocks={activity_data.get(\'mocks_done\',0)}, words={activity_data.get(\'words_looked\',0)}, chats={activity_data.get(\'ai_chats\',0)}, IELTS band={activity_data.get(\'last_ielts_band\',\'N/A\')}, CEFR={activity_data.get(\'last_cefr_level\',\'N/A\')}. End with tomorrow\'s tip."}\n            ],\n            max_tokens=300\n        )\n        return resp.choices[0].message.content\n    except Exception:\n        return "Bugun ham yaxshi ish qildingiz! Ertaga ham davom eting. 💪"\n')

